mapper.select:
SELECT COUNT(*) FROM work_order w LEFT JOIN product p ON w.product_id = p.product_id
w.is_deleted = FALSE
AND ( w.order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM work_order_client_order woco JOIN client_order co ON woco.cl_order_id = co.cl_order_id JOIN client cl ON co.client_id = cl.client_id WHERE woco.work_order_id = w.order_id AND cl.client_name LIKE CONCAT('%', #{keyword}, '%') ) )
AND w.status = #{status}
AND DATE(w.created_at) >= #{startDate}
AND DATE(w.created_at) <= #{endDate}

mapper.insert:
INSERT INTO work_order_client_order (
  work_order_id, cl_order_id, product_id, order_qty, created_at
) VALUES ( #{workOrderId}, #{clOrderId}, #{productId}, #{orderQty}, NOW() )

INSERT INTO work_order_material (
  work_order_id, material_id, required_qty, created_at
) VALUES ( #{workOrderId}, #{materialId}, #{requiredQty}, NOW() )

mapper.select:
SELECT order_id, order_qty, status, product_id, line_id
FROM work_order 
WHERE order_id = #{orderId}
